content.query:
let selectedLabel = '{LabelFilter}';
let startDate = startofday({TimeRange:start});
let endDate = startofday({TimeRange:end});
let priorities = dynamic(["High Severity", "Medium Severity", "Low Severity"]);
let allDates = range DateOnly from startDate to endDate step 1d;
let allCombinations = allDates
| extend Priority = priorities
| mv-expand Priority to typeof(string);
let riskData = EasmRisk_CL
| where SnapshotDateTime_t {TimeRange}
| join kind=leftouter (
    EasmAsset_CL
    | summarize arg_max(SnapshotDateTime_t, *) by AssetUuid_g
    | project AssetUuid_g, Labels_s
) on AssetUuid_g
| where selectedLabel == 'すべて' 
    or (selectedLabel == 'ラベルなし' and (isempty(Labels_s) or Labels_s == '' or Labels_s == '[]'))
    or (selectedLabel != 'すべて' and selectedLabel != 'ラベルなし' and Labels_s contains selectedLabel)
| extend SnapshotDateJST = datetime_add('hour', 9, SnapshotDateTime_t)
| extend DateOnly = startofday(SnapshotDateJST)
| summarize arg_max(SnapshotDateTime_t, *) by DateOnly, AssetUuid_g, MetricDisplayName_s
| summarize RiskCount = count() by DateOnly, Priority = CategoryName_s;
allCombinations
| join kind=leftouter (riskData) on DateOnly, Priority
| project DateOnly, Priority, RiskCount
| sort by DateOnly asc, Priority asc
